import java.io.*;
import java.util.*;

public class Main {
    private static boolean isValid(int[] arr, int D, int T) {
        long sum = 0;
        for (int v : arr) {
            sum += (v + D - 1) / D; // ceiling division
            if (sum > T) return false;
        }
        return true;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append(' ');
        }
        // Replace escaped newlines ("\\n") with spaces and also any real newlines
        String all = raw.toString().replace("\\n", " ").replace("\n", " ").trim();
        if (all.isEmpty()) return;
        StringTokenizer st = new StringTokenizer(all);
        int Q = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int q = 0; q < Q; q++) {
            int N = Integer.parseInt(st.nextToken());
            int T = Integer.parseInt(st.nextToken());
            int[] arr = new int[N];
            int maxA = 0;
            for (int i = 0; i < N; i++) {
                arr[i] = Integer.parseInt(st.nextToken());
                if (arr[i] > maxA) maxA = arr[i];
            }
            int left = 1, right = maxA, ans = maxA;
            while (left <= right) {
                int mid = left + (right - left) / 2;
                if (isValid(arr, mid, T)) {
                    ans = mid;
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            }
            out.append(ans);
            if (q != Q - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

